use std::collections::BinaryHeap;
use std::cmp::Ordering;

pub fn find_path_in_maze(maze: Vec<Vec<i32>>, start: (usize, usize), end: (usize, usize)) -> Option<Vec<(usize, usize)>> {
    if maze.is_empty() || maze[0].is_empty() {
        return None;
    }
    let rows = maze.len();
    let cols = maze[0].len();
    let (start_x, start_y) = start;
    let (end_x, end_y) = end;

    if start_x >= rows || start_y >= cols || maze[start_x][start_y] != 0 ||
       end_x >= rows || end_y >= cols || maze[end_x][end_y] != 0 {
        return None;
    }

    #[derive(Eq, PartialEq)]
    struct Node { x: usize, y: usize, g: i32, f: i32 }

    impl Ord for Node {
        fn cmp(&self, other: &Self) -> Ordering { other.f.cmp(&self.f) }
    }
    impl PartialOrd for Node {
        fn partial_cmp(&self, other: &Self) -> Option<Ordering> { Some(self.cmp(other)) }
    }

    let heuristic = |(x1, y1): (usize, usize), (x2, y2): (usize, usize)| -> i32 {
        (x1 as i32 - x2 as i32).abs() + (y1 as i32 - y2 as i32).abs()
    };

    let mut open_set = BinaryHeap::new();
    open_set.push(Node { x: start_x, y: start_y, g: 0, f: heuristic(start, end) });

    let mut came_from = vec![vec![None; cols]; rows];
    let mut g_scores = vec![vec![i32::MAX; cols]; rows];
    g_scores[start_x][start_y] = 0;

    let directions = [(-1, 0), (1, 0), (0, -1), (0, 1)];

    while let Some(current) = open_set.pop() {
        if current.x == end_x && current.y == end_y {
            let mut path = Vec::new();
            let mut current_pos = (end_x, end_y);
            while let Some(parent) = came_from[current_pos.0][current_pos.1] {
                path.push(current_pos);
                current_pos = parent;
            }
            path.push(start);
            path.reverse();
            return Some(path);
        }

        if current.g > g_scores[current.x][current.y] { continue; }

        for (dx, dy) in &directions {
            let nx = current.x as i32 + dx;
            let ny = current.y as i32 + dy;
            if nx < 0 || ny < 0 || nx >= rows as i32 || ny >= cols as i32 { continue; }
            let (nx, ny) = (nx as usize, ny as usize);
            if maze[nx][ny] != 0 { continue; }

            let tentative_g = current.g + 1;
            if tentative_g < g_scores[nx][ny] {
                came_from[nx][ny] = Some((current.x, current.y));
                g_scores[nx][ny] = tentative_g;
                let f = tentative_g + heuristic((nx, ny), end);
                open_set.push(Node { x: nx, y: ny, g: tentative_g, f });
            }
        }
    }

    None
}
