def min_operations(n):
    if n == 1:
        return 0

    from collections import deque
    visited = set()
    queue = deque([(n, 0)])

    while queue:
        current, steps = queue.popleft()
        if current == 1:
            return steps
        if current in visited:
            continue
        visited.add(current)

        # Subtract 1
        next_num = current - 1
        if next_num >= 1:
            queue.append((next_num, steps + 1))

        # Divide by all prime factors
        factors = set()
        num = current
        i = 2
        while i * i <= num:
            if num % i == 0:
                factors.add(i)
                while num % i == 0:
                    num //= i
            i += 1
        if num > 1:
            factors.add(num)

        for p in factors:
            if p == current:
                queue.append((1, steps + 1))
            else:
                next_num = current // p
                if next_num >= 1:
                    queue.append((next_num, steps + 1))

    return -1
