        dataPoints.forEach(point => {
            let minDist = Infinity;
            let clusterIndex = -1;
            centroids.forEach((centroid, idx) => {
                const dx = point.x - centroid.x;
                const dy = point.y - centroid.y;
                const dist = dx * dx + dy * dy;
                if (dist < minDist) {
                    minDist = dist;
                    clusterIndex = idx;
                }
            });
            if (clusterIndex !== -1) {
                sums[clusterIndex].sumX += point.x;
                sums[clusterIndex].sumY += point.y;
                sums[clusterIndex].count++;
            }
        });

        hasChanged = false;
        const newCentroids = [];
        for (let i = 0; i < k; i++) {
            const sum = sums[i];
            if (sum.count > 0) {
                const newX = sum.sumX / sum.count;
                const newY = sum.sumY / sum.count;
                newCentroids.push({ x: newX, y: newY });
