fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let n = graph.len();
    let mut visited = vec![false; n];
    let mut order = Vec::with_capacity(n);

    for u in 0..n {
        if !visited[u] {
            let mut stack = vec![(u, false)];
            while let Some((v, processed)) = stack.pop() {
                if processed {
                    order.push(v);
                } else {
                    if visited[v] { continue; }
                    visited[v] = true;
                    stack.push((v, true));
                    for &w in graph[v].iter().rev() {
                        if !visited[w] {
                            stack.push((w, false));
                        }
                    }
                }
            }
        }
    }

    let mut reversed_graph = vec![Vec::new(); n];
    for u in 0..n {
        for &v in &graph[u] {
            reversed_graph[v].push(u);
        }
    }

    let mut visited_rev = vec![false; n];
    let mut components = Vec::new();
    for &u in order.iter().rev() {
        if !visited_rev[u] {
            let mut component = Vec::new();
            let mut stack = vec![u];
            visited_rev[u] = true;
            while let Some(v) = stack.pop() {
                component.push(v);
                for &w in &reversed_graph[v] {
                    if !visited_rev[w] {
                        visited_rev[w] = true;
                        stack.push(w);
                    }
                }
            }
            components.push(component);
        }
    }

    components
}
