public class LongestRepeatedSubstring {
    public static String findLongestRepeatedSubstring(String s) {
        if (s == null || s.length() < 2) return "";
        int n = s.length();
        Integer[] suffixes = new Integer[n];
        for (int i = 0; i < n; i++) suffixes[i] = i;
        Arrays.sort(suffixes, (a, b) -> {
            int oa = a, ob = b;
            while (a < n && b < n && s.charAt(a) == s.charAt(b)) {
                a++;
                b++;
            }
            if (a == n && b == n) return Integer.compare(oa, ob);
            if (a == n) return -1;
            if (b == n) return 1;
            return s.charAt(a) - s.charAt(b);
        });
        int maxLen = 0;
        int startIdx = -1;
        for (int i = 0; i < n - 1; i++) {
            int a = suffixes[i], b = suffixes[i + 1];
            int len = 0;
            while (a < n && b < n && s.charAt(a) == s.charAt(b)) {
                a++;
                b++;
                len++;
            }
            if (len > maxLen) {
                maxLen = len;
                startIdx = suffixes[i];
            }
        }
        return maxLen > 0 ? s.substring(startIdx, startIdx + maxLen) : "";
    }
}
