            if (alt < dist[v]) {
                dist[v] = alt;
                if (pos[v] == -1) {
                    heap[heap_size] = (HeapNode){v, alt};
                    pos[v] = heap_size++;
                    int current = heap_size - 1;
                    while (current > 0) {
                        int parent = (current - 1) / 2;
                        if (heap[parent].distance > heap[current].distance) {
                            HeapNode temp = heap[parent];
                            heap[parent] = heap[current];
                            heap[current] = temp;
                            pos[heap[parent].vertex] = parent;
                            pos[heap[current].vertex] = current;
                            current = parent;
                        } else break;
                    }
                } else {
                    int current = pos[v];
                    if (alt < heap[current].distance) {
                        heap[current].distance = alt;
                        while (current > 0) {
                            int parent = (current - 1) / 2;
                            if (heap[parent].distance > heap[current].distance) {
                                HeapNode temp = heap[parent];
                                heap[parent] = heap[current];
                                heap[current] = temp;
                                pos[heap[parent].vertex] = parent;
                                pos[heap[current].vertex] = current;
                                current = parent;
                            } else break;
                        }
                    }
                }
            }
            edge = edge->next;
        }
    }

    free(heap);
    free(pos);
    return dist;
