class SuffixTree {
private:
    Node* root;
    Node* active_node;
    int active_edge;
    int active_length;
    int remaining;
    int global_end;
    string s;

    Node* split(Node* node, int pos, int split_point) {
        Node* split_node = new Node(node->start, split_point);
        Node* new_leaf = new Node(pos, global_end);
        split_node->children[s[split_point + 1]] = node;
        split_node->children[s[pos]] = new_leaf;
        node->start = split_point + 1;
        active_node->children[s[active_edge]] = split_node;
        return split_node;
    }

    void extend(int pos) {
        global_end = pos;
        remaining++;
        Node* last_new_node = nullptr;
        while (remaining > 0) {
            if (active_length == 0) active_edge = pos;
            auto it = active_node->children.find(s[active_edge]);
            if (it == active_node->children.end()) {
                Node* new_node = new Node(pos, global_end);
                active_node->children[s[active_edge]] = new_node;
                if (last_new_node != nullptr) {
                    last_new_node->suffix_link = active_node;
                    last_new_node = nullptr;
                }
                remaining--;
            } else {
                Node* next = it->second;
                int edge_len = next->end - next->start + 1;
                if (active_length >= edge_len) {
                    active_edge += edge_len;
                    active_length -= edge_len;
                    active_node = next;
                    continue;
                }
                if (s[next->start + active_length] == s[pos]) {
                    active_length++;
                    if (last_new_node != nullptr) {
                        last_new_node->suffix_link = active_node;
                        last_new_node = nullptr;
                    }
                    break;
                }
                Node* split_node = split(next, pos, next->start + active_length);
                if (last_new_node != nullptr) last_new_node->suffix_link = split_node;
                last_new_node = split_node;
                if (active_node == root) {
                    active_edge++;
                    active_length--;
                } else {
                    active_node = active_node->suffix_link;
                }
                remaining--;
            }
        }
    }

public:
    SuffixTree(const string& str) : s(str) {
        root = new Node(-1, -1);
        active_node = root;
        active_length = 0;
        remaining = 0;
        global_end = -1;
        for (int i = 0; i < s.size(); i++) extend(i);
    }

    string longest_repeated_substring() {
        string result;
        int max_len = 0;
        function<void(Node*, string)> dfs = [&](Node* node, string current) {
            if (node != root) {
                int edge_len = node->end - node->start + 1;
                current += s.substr(node->start, edge_len);
            }
            if (node->children.size() > 1 && current.length() > max_len) {
                max_len = current.length();
                result = current;
            }
            for (auto& child : node->children) dfs(child.second, current);
        };
        dfs(root, "");
        return result;
    }
};

string longest_repeated_substring(string s) {
    if (s.empty()) return "";
    SuffixTree st(s);
    return st.longest_repeated_substring();
}
