int substring_search(char *text, char *pattern) {
    int m = strlen(pattern);
    int n = strlen(text);

    if (m == 0) return 0;
    if (n == 0) return -1;

    int *lps = (int *)malloc(m * sizeof(int));
    if (!lps) return -1;

    lps[0] = 0;
    int len = 0, i = 1;
    while (i < m) {
        if (pattern[i] == pattern[len]) {
            lps[i++] = ++len;
        } else {
            if (len != 0) len = lps[len - 1];
            else lps[i++] = 0;
        }
    }

    i = 0;
    int j = 0;
    while (i < n) {
        if (pattern[j] == text[i]) { j++; i++; }
        if (j == m) {
            free(lps);
            return i - j;
        } else if (i < n && pattern[j] != text[i]) {
            if (j != 0) j = lps[j - 1];
            else i++;
        }
    }

    free(lps);
    return -1;
}
