import java.util.*;

public class HuffmanCompressor {
    public static String compressData(String input) {
        if (input.isEmpty()) return input;

        Map<Character, Integer> freq = new HashMap<>();
        for (char c : input.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }

        PriorityQueue<Node> pq = new PriorityQueue<>();
        for (Map.Entry<Character, Integer> entry : freq.entrySet()) {
            pq.add(new Node(entry.getKey(), entry.getValue()));
        }

        while (pq.size() > 1) {
            Node left = pq.poll();
            Node right = pq.poll();
            Node parent = new Node(null, left.freq + right.freq);
            parent.left = left;
            parent.right = right;
            pq.add(parent);
        }

        Node root = pq.poll();
        Map<Character, String> codes = new HashMap<>();
        buildCodes(root, "", codes);

        StringBuilder encoded = new StringBuilder();
        for (char c : input.toCharArray()) {
            encoded.append(codes.get(c));
        }

        StringBuilder freqStr = new StringBuilder();
        for (Map.Entry<Character, Integer> entry : freq.entrySet()) {
            if (freqStr.length() > 0) {
                freqStr.append(",");
            }
            freqStr.append((int) entry.getKey()).append(":").append(entry.getValue());
        }
        freqStr.append("|").append(encoded);

        return freqStr.toString();
    }

    private static void buildCodes(Node node, String code, Map<Character, String> codes) {
        if (node == null) return;
        if (node.left == null && node.right == null) {
            if (code.isEmpty()) {
                code = "0";
            }
            codes.put(node.c, code);
            return;
        }
        buildCodes(node.left, code + "0", codes);
        buildCodes(node.right, code + "1", codes);
    }

    static class Node implements Comparable<Node> {
        Character c;
        int freq;
        Node left, right;

        Node(Character c, int freq) {
            this.c = c;
            this.freq = freq;
        }

        @Override
        public int compareTo(Node other) {
            return this.freq - other.freq;
        }
    }
}
