fn merge_sort_list<T: Ord>(head: Option<Box<Node<T>>>) -> Option<Box<Node<T>>> {
    if head.as_ref().map_or(true, |n| n.next.is_none()) {
        return head;
    }

    let (left, right) = split(head);
    let left = merge_sort_list(left);
    let right = merge_sort_list(right);
    merge(left, right)
}

fn split<T>(mut head: Option<Box<Node<T>>>) -> (Option<Box<Node<T>>>, Option<Box<Node<T>>>) {
    let mut len = 0;
    let mut current = &head;
    while let Some(node) = current {
        len += 1;
        current = &node.next;
    }
    if len <= 1 {
        return (head, None);
    }
    let mid = len / 2;
    let mut current = &mut head;
    for _ in 0..mid - 1 {
        current = &mut current.as_mut().unwrap().next;
    }
    let right = current.as_mut().unwrap().next.take();
    (head, right)
}

fn merge<T: Ord>(
    mut left: Option<Box<Node<T>>>,
    mut right: Option<Box<Node<T>>>,
) -> Option<Box<Node<T>>> {
    let mut head = None;
    let mut tail = &mut head;

    while left.is_some() && right.is_some() {
        if left.as_ref().unwrap().value <= right.as_ref().unwrap().value {
            let next = left.as_mut().unwrap().next.take();
            *tail = left;
            left = next;
        } else {
            let next = right.as_mut().unwrap().next.take();
            *tail = right;
            right = next;
        }
        tail = &mut tail.as_mut().unwrap().next;
    }

    if left.is_some() {
        *tail = left;
    } else {
        *tail = right;
    }

    head
}
