bool bfs(int n, int residual[n][n], int source, int sink, int parent[]) {
    bool visited[n];
    for (int i = 0; i < n; i++) visited[i] = false;
    int queue[n], front = 0, rear = 0;
    queue[rear++] = source;
    visited[source] = true;
    parent[source] = -1;

    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (!visited[v] && residual[u][v] > 0) {
                parent[v] = u;
                visited[v] = true;
                queue[rear++] = v;
                if (v == sink) return true;
            }
        }
    }
    return false;
}

int find_max_flow(int n, int graph[n][n], int source, int sink) {
    int residual[n][n];
    for (int i = 0; i < n; i++)
        for (int j = 0; j < n; j++)
            residual[i][j] = graph[i][j];

    int parent[n];
    int max_flow = 0;

    while (bfs(n, residual, source, sink, parent)) {
        int path_flow = INT_MAX;
        for (int v = sink; v != source; v = parent[v])
            path_flow = residual[parent[v]][v] < path_flow ? residual[parent[v]][v] : path_flow;
        for (int v = sink; v != source; v = parent[v]) {
            int u = parent[v];
            residual[u][v] -= path_flow;
            residual[v][u] += path_flow;
        }
        max_flow += path_flow;
    }
    return max_flow;
