bool isAnagram(string s, string t) {
    if (s.size() != t.size()) return false;

    const int HASH_SIZE = 64;
    auto computeSimHash = [](const string &str) -> bitset<HASH_SIZE> {
        int counts[256] = {0};
        for (unsigned char c : str) counts[c]++;
        vector<int> sim_vector(HASH_SIZE, 0);
        for (int i = 0; i < 256; ++i) {
            int count = counts[i];
            if (!count) continue;
            size_t hash = hash<unsigned char>()(static_cast<unsigned char>(i));
            for (int j = 0; j < HASH_SIZE; ++j) {
                if (hash & (1ULL << j)) sim_vector[j] += count;
                else sim_vector[j] -= count;
            }
        }
        bitset<HASH_SIZE> result;
        for (int j = 0; j < HASH_SIZE; ++j)
            if (sim_vector[j] > 0) result.set(j);
        return result;
    };

    return computeSimHash(s) == computeSimHash(t);
